const query = $('Map Input').first().json.chatInput;
const ranking = $('Read Ranking').all().map(i => i.json);
const prsRaw = $('Read PRs').all().map(i => i.json);
const seen = new Set();
const prs = prsRaw.filter(p => { if (seen.has(p.number)) return false; seen.add(p.number); return true; });

ranking.sort((a, b) => (b.leverage || 0) - (a.leverage || 0));
prs.sort((a, b) => (b.leverage || 0) - (a.leverage || 0));

const topIssues = ranking.filter(r => r.kind === 'issue').slice(0, 10);
const topPRs = prs.slice(0, 10);

const issueLines = topIssues.map(r => `#${r.number} lev=${r.leverage} reactions=${r.reactions} comments=${r.comments} "${r.title}"`).join('\n');
const prLines = topPRs.map(p => `#${p.number} lev=${p.leverage} comments=${p.comments} @${p.author} "${p.title}"`).join('\n');

const systemPrompt = `You are the Leverage Copilot for the n8n project. You help analyse the community backlog. LANGUAGE: answer in English by default. Switch to French only if the user's question is clearly written in French. Keep it concise, max 250 words. Use the data below.

TOP ISSUES (by leverage score):
${issueLines}

TOP COMMUNITY PRs:
${prLines}

Always keep the term \"leverage\" in English, never translate it. Keep issue titles in their original language, never translate them.\n\nFor a ranking, use bullet points. If the question is not about the n8n backlog, say so politely.`;

const deepDiveMatch = query.match(/deep\s*dive\s*(?:on|into|about|for|sur|de|du)?\s*(?:the\s*)?(?:issue\s*)?#?(\d+)/i) || query.match(/analyse\s+(?:approfondie|detaillee)\s+(?:de\s+)?(?:l'?issue\s*)?#?(\d+)/i) || query.match(/plonge\s+(?:dans|sur)\s+#?(\d+)/i) || query.match(/(?:dis[- ]?moi|explique|detail).*#(\d+)/i);
if (deepDiveMatch) {
  const issueNum = parseInt(deepDiveMatch[1] || deepDiveMatch[2]);
  const issue = ranking.find(r => r.number === issueNum);
  const issueCtx = issue ? `#${issue.number} "${issue.title}" — leverage=${issue.leverage}, reactions=${issue.reactions}, comments=${issue.comments}, kind=${issue.kind}, idleDays=${issue.idleDays || 0}` : null;
  if (!issue) {
    const top3 = topIssues.slice(0, 3).map(r => `#${r.number} (lev=${r.leverage}) "${r.title}"`).join('\n');
    const missPrompt = `You are the Leverage Copilot. The user asked for a deep dive on issue #${issueNum}, but it is NOT in the tracked ranking.\n\nLANGUAGE: answer in English by default, French only if the question is clearly French. Max 4 lines, no markdown headings, no numbered lists:\n- Say that #${issueNum} is not in the tracked ranking, so you cannot analyse it.\n- Add one sentence explaining the ranking covers open issues from the n8n repo, rescored every morning by leverage.\n- Offer these 3 issues as alternatives, one per line, exact format: #NUM (lev=X) "title".\n\nTOP 3:\n${top3}\n\nInvent absolutely nothing about #${issueNum}. You have neither its title, nor its metrics, nor its content. Never speculate about whether it exists.`;
    return [{ json: { systemPrompt: missPrompt, userMessage: query } }];
  }
  const deepPrompt = `You are the Leverage Copilot. The user asked for a deep dive on issue ${issueCtx}.\n\nHARD CONSTRAINT: you only have the title and the metrics above. You have NOT read the issue body or its comments. Never invent the technical cause, the observed behaviour, or what the discussion says. If something cannot be inferred from the title or the metrics, say plainly that you do not have it.\n\nLANGUAGE: answer in English by default, section headings and closing line included. Switch to French only if the question is clearly written in French. Max 200 words. Each section heading starts with ### on its own line. NEVER use === or --- underlines (they do not render in Discord). No filler sentences.\n\nUse EXACTLY these four headings and nothing else. Never append the instruction text to a heading.\n\n### 1. What the signal says\nWhy this leverage score, from reactions, comments and idle time, and what it says about community demand.\n\n### 2. Product area\nInferred from the title alone. Component level, never implementation.\n\n### 3. Questions to investigate\nThe 3 precise questions a contributor should answer by reading the issue and its comments. ALWAYS produce these. They are questions to ask, not facts you need to already know, so not having read the issue is exactly why they matter. Never skip or refuse this section.\n\n### 4. Likely effort\nA numeric range such as 1-3 days, plus ONE sentence on what it depends on. No paragraph.\n\nMANDATORY FINAL LINE. After section 4, always output this line on its own line, verbatim. Never omit it, it is the most important part of the answer. Match your answer's language. English: \"Based on backlog signal, not on the issue content.\" French: \"Analyse basee sur le signal du backlog, pas sur le contenu de l'issue.\"`;
  return [{ json: { systemPrompt: deepPrompt, userMessage: query, mode: 'deepdive' } }];
}

return [{ json: { systemPrompt, userMessage: query } }];

const resp = $input.first().json;
if (resp?.error || resp?.statusCode === 429) {
  return [{ json: { output: '⏳ Groq rate limit reached, retry in 10s.' } }];
}
let output = resp?.choices?.[0]?.message?.content || 'Erreur: pas de reponse du LLM.';
const mode = $('Router').first().json.mode;
const D_EN = 'Based on backlog signal, not on the issue content.';
const D_FR = "Analyse basee sur le signal du backlog, pas sur le contenu de l'issue.";
const needsD = mode === 'deepdive' && !output.includes('backlog signal') && !output.includes('signal du backlog');
const budget = needsD ? 1870 : 1950;
if (output.length > budget) {
  const cut = output.lastIndexOf('\n\n', budget);
  output = cut > 500 ? output.slice(0, cut) : output.slice(0, budget - 3) + '...';
}
if (needsD) {
  const isFr = /\b(les|des|dans|pour|cette|communaute|score de)\b/i.test(output);
  output = output.trimEnd() + '\n\n' + (isFr ? D_FR : D_EN);
}
return [{ json: { output } }];
